solution: ```class Solution {
public:
    bool detectCapitalUse(string word) {
        int n = word.size();
        int caps = 0;
        for (char c : word) if (isupper(c)) ++caps;
        if (caps == 0 || caps == n) return true;
        return caps == 1 && isupper(word[0]);
    }
};```
